import { useEffect, useMemo } from 'react';
import { Flex, Text } from '@chakra-ui/react';
import { useFormContext } from 'react-hook-form';
import { Trans, useTranslation } from 'react-i18next';
import { FormSingleCheckboxControl } from '@ui/components/formControls/CheckboxControl';
import { FormAddressControl } from '@ui/components/formControls/compositions/AddressControl';
import { Label, Meta } from '@ui/components/typography';

type Props = {
  accountSlug?: string;
};

export const Addresses = ({ accountSlug }: Props) => {
  const { t } = useTranslation('organizationApplication', { keyPrefix: 'legalEntity' });
  const { t: tCommon } = useTranslation('common');

  const { setValue, watch } = useFormContext();
  const legalAddressLine1 = watch('line1');
  const usePhysicalAddress = watch('usePhysicalAddress');
  const useMailingAddress = watch('useMailingAddress');

  const isPOBox = useMemo(
    () =>
      legalAddressLine1
        ?.toLowerCase()
        .match(
          /^\s*(.*((p|post)[-.\s]*(o|off|office)[-.\s]*(b|box|bin)[-.\s]*)|.*((p|post)[-.\s]*(o|off|office)[-.\s]*)|.*((p|post)[-.\s]*(b|box|bin)[-.\s]*)|(box|bin)[-.\s]*)(#|n|num|number)?\s*\d+/i
        ),
    [legalAddressLine1]
  );

  useEffect(() => {
    if (isPOBox) {
      setValue('usePhysicalAddress', false);
    }
  }, [isPOBox, setValue]);

  return (
    <>
      <Flex direction="column" gap={2}>
        <Label variant="bold">{t('legalAddress.heading')}</Label>
        <Meta>
          <Trans
            components={[
              <Text
                as="span"
                color="red.500"
                display="block"
                key="legal-address-description-text"
              />,
            ]}
            i18nKey="legalAddress.description"
            t={t}
          />
        </Meta>
        <FormAddressControl
          accountSlug={accountSlug}
          allowedCountries={['US']}
          isRequired
          label={tCommon('street')}
        />
      </Flex>
      <Flex direction="column" gap={2}>
        <FormSingleCheckboxControl
          formControlProps={{ fontWeight: 'bold' }}
          isDisabled={isPOBox}
          name="usePhysicalAddress"
        >
          {t('physicalAddress.checkbox.label')}
        </FormSingleCheckboxControl>
        {isPOBox ? (
          <Text as="span" color="red.500" display="block" textStyle="metaRegular">
            {t('legalAddress.noPoBox')}
          </Text>
        ) : null}
        <Meta>
          <Trans
            components={[<b key="physical-address-checkbox-description-text" />]}
            i18nKey="physicalAddress.checkbox.description"
            t={t}
          />
        </Meta>
        {!usePhysicalAddress && (
          <FormAddressControl
            accountSlug={accountSlug}
            allowedCountries={['US']}
            fieldPrefix="physical"
            isRequired
            label={tCommon('street')}
          />
        )}
      </Flex>
      <Flex direction="column" gap={2}>
        <FormSingleCheckboxControl
          formControlProps={{ fontWeight: 'bold' }}
          name="useMailingAddress"
        >
          {t('mailingAddress.checkbox.label')}
        </FormSingleCheckboxControl>
        <Meta>{t('mailingAddress.checkbox.description')}</Meta>
        {!useMailingAddress && (
          <FormAddressControl
            accountSlug={accountSlug}
            allowedCountries={['US']}
            fieldPrefix="mailing"
            isRequired
            label={tCommon('street')}
          />
        )}
      </Flex>
    </>
  );
};
